//! Integration tests using a real himbaechel example arch chipdb (10x10 grid).
//!
//! The chipdb is generated by `tests/fixtures/build_chipdb.sh` from the example
//! arch Python generator and committed as `tests/fixtures/example.bin`.

mod common;

use nextpnr::chipdb::{BelId, ChipDb, TileTypePod};
use nextpnr::common::PlaceStrength;
use nextpnr::context::{BelPin, Context};
use nextpnr::placer::heap::{place_heap, PlacerHeapCfg};
use nextpnr::read_packed;
use nextpnr::router::router1::Router1Cfg;
use nextpnr::router::{Router, Router1};
use nextpnr::timing::ClockEdge;

// =====================================================================
// Test helpers
// =====================================================================

/// Find the first BEL of a given type in the chipdb.
fn find_bel(ctx: &Context, bel_type: &str) -> BelId {
    ctx.chipdb()
        .bels()
        .find(|&bel| ctx.chipdb().bel_type(bel) == bel_type)
        .unwrap_or_else(|| panic!("should find a {} BEL", bel_type))
}

/// Find the first tile of a given type in the chipdb.
fn find_tile(chipdb: &ChipDb, tile_type: &str) -> i32 {
    (0..chipdb.num_tiles())
        .find(|&t| chipdb.tile_type_name(t) == tile_type)
        .unwrap_or_else(|| panic!("should find a {} tile", tile_type))
}

/// Get the wire name string for a tile-type wire entry.
fn tile_wire_name<'a>(chipdb: &'a ChipDb, wire: &nextpnr::chipdb::TileWireDataPod) -> &'a str {
    let name_id: i32 = unsafe { read_packed!(*wire, name) };
    chipdb.constid_str(name_id).unwrap_or("<unknown>")
}

/// Find a wire index by name within a tile type.
fn find_wire_in_tile(chipdb: &ChipDb, tt: &TileTypePod, name: &str) -> usize {
    tt.wires
        .get()
        .iter()
        .enumerate()
        .find_map(|(i, w)| (tile_wire_name(chipdb, w) == name).then_some(i))
        .unwrap_or_else(|| panic!("tile should have wire {name}"))
}

/// Collect the names of source wires for all uphill PIPs of a given wire.
fn uphill_source_names(chipdb: &ChipDb, tt: &TileTypePod, wire_idx: usize) -> Vec<String> {
    let wire = &tt.wires.get()[wire_idx];
    wire.pips_uphill
        .get()
        .iter()
        .map(|&pip_idx| {
            let pip = &tt.pips.get()[pip_idx as usize];
            let src_idx: i32 = unsafe { read_packed!(*pip, src_wire) };
            tile_wire_name(chipdb, &tt.wires.get()[src_idx as usize]).to_string()
        })
        .collect()
}

/// Collect the names of destination wires for all downhill PIPs of a given wire.
fn downhill_dest_names(chipdb: &ChipDb, tt: &TileTypePod, wire_idx: usize) -> Vec<String> {
    let wire = &tt.wires.get()[wire_idx];
    wire.pips_downhill
        .get()
        .iter()
        .map(|&pip_idx| {
            let pip = &tt.pips.get()[pip_idx as usize];
            let dst_idx: i32 = unsafe { read_packed!(*pip, dst_wire) };
            tile_wire_name(chipdb, &tt.wires.get()[dst_idx as usize]).to_string()
        })
        .collect()
}

/// Find a constid index by its string name.
fn find_constid(chipdb: &ChipDb, name: &str) -> i32 {
    let total = chipdb.extra_constids().len() as i32;
    (0..total)
        .find(|&i| chipdb.constid_str(i).map_or(false, |s| s == name))
        .unwrap_or_else(|| panic!("{name} constid should exist"))
}

/// Collect all wire names in a tile type.
fn all_wire_names<'a>(chipdb: &'a ChipDb, tt: &TileTypePod) -> Vec<&'a str> {
    tt.wires.get().iter().map(|w| tile_wire_name(chipdb, w)).collect()
}

