// =====================================================================
// Wire and PIP traversal
// =====================================================================

#[test]
fn pip_src_dst_wires_are_valid() {
    let ctx = common::make_example_context();
    let chipdb = ctx.chipdb();

    let pips: Vec<_> = chipdb.pips().take(100).collect();
    assert_eq!(pips.len(), 100, "chipdb should have at least 100 PIPs");

    for pip in pips {
        let src = chipdb.pip_src_wire(pip);
        let dst = chipdb.pip_dst_wire(pip);
        assert_eq!(src.tile(), pip.tile());
        assert_eq!(dst.tile(), pip.tile());
        let tt = chipdb.tile_type(pip.tile());
        assert!((src.index() as usize) < tt.wires.get().len());
        assert!((dst.index() as usize) < tt.wires.get().len());
    }
}

#[test]
fn wire_names_are_valid() {
    let ctx = common::make_example_context();
    let chipdb = ctx.chipdb();

    let logic_tile = find_tile(chipdb, "LOGIC");
    let tt = chipdb.tile_type(logic_tile);
    for wire_idx in 0..tt.wires.get().len().min(5) {
        let wire_id = nextpnr::chipdb::WireId::new(logic_tile, wire_idx as i32);
        let name = chipdb.wire_name(wire_id);
        assert!(!name.is_empty());
        assert_ne!(name, "<unknown>");
    }
}

// =====================================================================
// Tile name resolution
// =====================================================================

#[test]
fn tile_names_and_types() {
    let ctx = common::make_example_context();
    let chipdb = ctx.chipdb();

    // Corner tiles should be NULL type
    let corner = chipdb.tile_by_xy(0, 0);
    assert_eq!(chipdb.tile_type_name(corner), "NULL");

    // Edge tiles (non-corner) should be IO
    let edge = chipdb.tile_by_xy(0, 1);
    assert_eq!(chipdb.tile_type_name(edge), "IO");

    // Interior tiles should be LOGIC (except BRAM rows)
    let interior = chipdb.tile_by_xy(1, 1);
    assert_eq!(chipdb.tile_type_name(interior), "LOGIC");

    // Check BRAM row (y%15==7)
    let bram = chipdb.tile_by_xy(1, 7);
    assert_eq!(chipdb.tile_type_name(bram), "BRAM");

    // tile_name should produce a readable string
    let name = chipdb.tile_name(interior);
    assert!(name.contains("X1Y1"), "tile name should contain coordinates, got: {name}");
}

#[test]
fn tile_xy_roundtrip() {
    let ctx = common::make_example_context();
    let chipdb = ctx.chipdb();

    for y in 0..chipdb.height() {
        for x in 0..chipdb.width() {
            let tile = chipdb.tile_by_xy(x, y);
            let (rx, ry) = chipdb.tile_xy(tile);
            assert_eq!((rx, ry), (x, y));
        }
    }
}

