// =====================================================================
// HeAP placement with real chipdb
// =====================================================================

#[test]
fn heap_placement_small() {
    let mut ctx = common::make_example_context_with_cells(4);
    let cfg = PlacerHeapCfg {
        seed: 42,
        max_iterations: 5,
        ..PlacerHeapCfg::default()
    };
    place_heap(&mut ctx, &cfg).expect("HeAP should succeed on example chipdb");

    for cell in ctx.cells() {
        if !cell.is_alive() {
            continue;
        }
        assert!(
            cell.bel_id().is_some(),
            "cell {} should be placed",
            cell.name()
        );
    }
}

#[test]
fn heap_placement_medium() {
    let mut ctx = common::make_example_context_with_cells(16);
    let cfg = PlacerHeapCfg {
        seed: 99,
        max_iterations: 10,
        ..PlacerHeapCfg::default()
    };
    place_heap(&mut ctx, &cfg).expect("HeAP should handle 16 cells");

    let mut placed = std::collections::HashSet::new();
    for cell in ctx.cells() {
        if !cell.is_alive() {
            continue;
        }
        let bel = cell.bel_id().expect("cell should be placed");
        assert!(placed.insert(bel), "each cell should be on a unique BEL");
    }
    assert_eq!(placed.len(), 16);
}

