#[test]
fn lut4_combinational_delays() {
    // LUT4 should have comb arcs I[0]->F: 150ps, I[1]->F: 165ps, I[2]->F: 180ps, I[3]->F: 195ps
    let ctx = common::make_example_context();
    let chipdb = ctx.chipdb();
    let sg = chipdb.speed_grade(0).unwrap();

    let lut4_id = find_constid(chipdb, "LUT4");
    let f_id = find_constid(chipdb, "F");
    let type_idx = chipdb.cell_timing_index(&sg, lut4_id).expect("LUT4 should have timing data");

    let expected_delays = [(150, "I[0]"), (165, "I[1]"), (180, "I[2]"), (195, "I[3]")];
    for (expected_ps, pin_name) in &expected_delays {
        let pin_id = find_constid(chipdb, pin_name);
        let delay = chipdb
            .cell_delay(&sg, type_idx, pin_id, f_id)
            .unwrap_or_else(|| panic!("LUT4 should have {pin_name}->F delay"));

        assert_eq!(
            delay.max_delay(),
            *expected_ps,
            "LUT4 {pin_name}->F delay should be {expected_ps}ps"
        );
    }
}

#[test]
fn dff_register_timing() {
    // DFF should have: setup(CLK,D)=150ps, hold=25ps, clk_to_q(CLK,Q)=200ps
    let ctx = common::make_example_context();
    let chipdb = ctx.chipdb();
    let sg = chipdb.speed_grade(0).unwrap();

    let dff_id = find_constid(chipdb, "DFF");
    let d_id = find_constid(chipdb, "D");
    let q_id = find_constid(chipdb, "Q");

    let type_idx = chipdb.cell_timing_index(&sg, dff_id).expect("DFF should have timing data");

    // Check D pin has register arcs (setup/hold)
    let d_arcs = chipdb
        .cell_reg_arcs(&sg, type_idx, d_id)
        .expect("DFF D pin should have register arcs");
    assert!(!d_arcs.is_empty(), "DFF D should have setup/hold arcs");

    let d_arc_info = nextpnr::chipdb::ChipDb::reg_arc_info(&d_arcs[0]);
    assert_eq!(d_arc_info.edge, ClockEdge::Rising, "DFF should be rising edge");
    // Setup time: TimingValue(150) → all corners = 150
    assert_eq!(d_arc_info.setup.max_delay, 150, "DFF setup should be 150ps");
    // Hold time: TimingValue(25) → all corners = 25
    assert_eq!(d_arc_info.hold.max_delay, 25, "DFF hold should be 25ps");

    // Check Q pin has register arcs (clock-to-Q)
    let q_arcs = chipdb
        .cell_reg_arcs(&sg, type_idx, q_id)
        .expect("DFF Q pin should have register arcs");
    assert!(!q_arcs.is_empty(), "DFF Q should have clk-to-Q arcs");

    let q_arc_info = nextpnr::chipdb::ChipDb::reg_arc_info(&q_arcs[0]);
    assert_eq!(q_arc_info.edge, ClockEdge::Rising);
    assert_eq!(
        q_arc_info.clock_to_q.max_delay(),
        200,
        "DFF clk-to-Q should be 200ps"
    );
}

#[test]
fn pip_timing_values_match_generator() {
    // SWINPUT class: delay=80ps, SWNEIGH class: delay=120ps
    let ctx = common::make_example_context();
    let chipdb = ctx.chipdb();
    let sg = chipdb.speed_grade(0).unwrap();

    let logic_tile = find_tile(chipdb, "LOGIC");
    let tt = chipdb.tile_type(logic_tile);

    // Collect all unique PIP timing indices and their delays
    let mut seen_delays = std::collections::HashSet::new();
    for (pip_idx, _pip) in tt.pips.get().iter().enumerate() {
        let pip_id = nextpnr::chipdb::PipId::new(logic_tile, pip_idx as i32);
        if let Some(pip_tmg) = chipdb.pip_timing(&sg, pip_id) {
            let int_delay = unsafe { read_packed!(*pip_tmg, int_delay) };
            seen_delays.insert(int_delay.slow_max);
        }
    }

    // We should see the SWINPUT (80ps) and SWNEIGH (120ps) delay values
    assert!(
        seen_delays.contains(&80),
        "should find SWINPUT delay of 80ps, got: {seen_delays:?}"
    );
    assert!(
        seen_delays.contains(&120),
        "should find SWNEIGH delay of 120ps, got: {seen_delays:?}"
    );
}

