#[test]
fn bram_tile_has_expected_bel_pins() {
    // BRAM_512X16 should have: CLK + 9 WA + 9 RA + 2 WE + 16 DI + 16 DO = 53 pins
    let ctx = common::make_example_context();
    let chipdb = ctx.chipdb();
    let bram_bel = find_bel(&ctx, "BRAM_512X16");
    let bel_info = chipdb.bel_info(bram_bel);

    let pin_count = bel_info.pins.get().len();
    assert_eq!(pin_count, 53, "BRAM should have 53 pins (CLK + 9WA + 9RA + 2WE + 16DI + 16DO)");

    let mut input_count = 0;
    let mut output_count = 0;
    for pin in bel_info.pins.get() {
        let (_name_id, _wire, dir) = chipdb.bel_pin_fields(pin);
        match dir {
            0 => input_count += 1,
            1 => output_count += 1,
            _ => {}
        }
    }
    // CLK + 9 WA + 9 RA + 2 WE + 16 DI = 37 inputs
    assert_eq!(input_count, 37, "BRAM should have 37 input pins");
    // 16 DO = 16 outputs
    assert_eq!(output_count, 16, "BRAM should have 16 output pins");
}

#[test]
fn all_bel_pin_wires_resolve() {
    // Every BEL pin across the entire chipdb should resolve to a valid wire
    let ctx = common::make_example_context();
    let chipdb = ctx.chipdb();
    let mut total_pins = 0;

    for bel_id in chipdb.bels() {
        let bel_info = chipdb.bel_info(bel_id);
        for pin in bel_info.pins.get() {
            let (name_id, wire_idx, _dir) = chipdb.bel_pin_fields(pin);
            let tt = chipdb.tile_type(bel_id.tile());
            assert!(
                (wire_idx as usize) < tt.wires.get().len(),
                "BEL pin wire index {} out of range for tile {}",
                wire_idx,
                bel_id.tile()
            );

            // Also verify via the Context API
            let pin_name = chipdb.constid_str(name_id).unwrap_or("?");
            let port = ctx.id(pin_name);
            let bp = BelPin::new(bel_id, port);
            assert!(
                ctx.bel_pin_wire(bp).is_some(),
                "bel_pin_wire should resolve for BEL {} pin {}",
                chipdb.bel_name(bel_id),
                pin_name
            );
            total_pins += 1;
        }
    }
    // Sanity check: we should have checked a large number of pins
    assert!(total_pins > 1000, "should check many pins, got {total_pins}");
}

