// =====================================================================
// Routing on real chipdb
// =====================================================================

/// Find LUT4 BELs in a single LOGIC tile where routing from driver to consumers
/// is possible within the tile's switch matrix.
///
/// The example arch switch matrix has a staggered pattern:
///   L(n)_O -> SWITCH(n*6 mod 60) -> L(m)_I(k)
/// So L2_O -> SWITCH4 -> L1_I0 works (driver=L2, consumer=L1 via I[0]).
///
/// Returns (driver_bel, consumer_bels) where driver_bel's F output can reach
/// each consumer_bel's I[0] input through the intra-tile switch matrix.
fn find_routable_lut4_bels(ctx: &Context) -> (BelId, Vec<BelId>) {
    let chipdb = ctx.chipdb();
    let logic_tile = (0..chipdb.num_tiles())
        .find(|&t| chipdb.tile_type_name(t) == "LOGIC")
        .expect("should have a LOGIC tile");

    let mut lut4_bels: Vec<BelId> = chipdb
        .bels()
        .filter(|&bel| bel.tile() == logic_tile && chipdb.bel_type(bel) == "LUT4")
        .collect();
    lut4_bels.sort_by_key(|b| b.index());

    // Find a driver whose F output can reach other LUT I[0] inputs via the switch matrix.
    let f_port = ctx.id("F");
    let i0_port = ctx.id("I[0]");
    for &driver_bel in &lut4_bels {
        let src_wire = match ctx.bel_pin_wire(BelPin::new(driver_bel, f_port)) {
            Some(w) => w.id(),
            None => continue,
        };
        // Find which consumer BELs' I[0] pins are reachable from this driver
        let mut reachable = Vec::new();
        for &consumer_bel in &lut4_bels {
            if consumer_bel == driver_bel {
                continue;
            }
            let sink_wire = match ctx.bel_pin_wire(BelPin::new(consumer_bel, i0_port)) {
                Some(w) => w.id(),
                None => continue,
            };
            // Check 2-hop: src_wire -> SWITCH -> sink_wire
            let src_info = chipdb.wire_info(src_wire);
            let reachable_via_switch = src_info.pips_downhill.get().iter().any(|&pip_idx| {
                let pip = nextpnr::chipdb::PipId::new(logic_tile, pip_idx);
                let sw_wire = chipdb.pip_dst_wire(pip);
                let sw_info = chipdb.wire_info(sw_wire);
                sw_info.pips_downhill.get().iter().any(|&pip_idx2| {
                    let pip2 = nextpnr::chipdb::PipId::new(logic_tile, pip_idx2);
                    chipdb.pip_dst_wire(pip2) == sink_wire
                })
            });
            if reachable_via_switch {
                reachable.push(consumer_bel);
            }
        }
        if !reachable.is_empty() {
            return (driver_bel, reachable);
        }
    }
    panic!("could not find any routable LUT4 driver->consumer pair in a single tile");
}

#[test]
fn route_single_net_on_real_chipdb() {
    let mut ctx = common::make_example_context_with_cells(2);

    // Place cells on BELs where the driver's F output can reach the
    // consumer's I[0] input through the intra-tile switch matrix.
    let (driver_bel, consumers) = find_routable_lut4_bels(&ctx);
    let cell0 = ctx.design.cell_by_name(ctx.id("cell_0")).unwrap();
    let cell1 = ctx.design.cell_by_name(ctx.id("cell_1")).unwrap();
    assert!(ctx.bind_bel(driver_bel, cell0, PlaceStrength::Placer));
    assert!(ctx.bind_bel(consumers[0], cell1, PlaceStrength::Placer));

    let router_cfg = Router1Cfg::default();
    let net_name = ctx.id("net_0");
    let net_idx = ctx.design.net_by_name(net_name).unwrap();

    Router1
        .route_net(&mut ctx, &router_cfg, net_idx)
        .expect("routing single net should succeed");

    // Verify the net has routed wires
    let net = ctx.net(net_idx);
    assert!(
        net.wires().len() >= 2,
        "routed net should have at least source + sink wires, got {}",
        net.wires().len()
    );
}

#[test]
fn route_nets_subset() {
    let mut ctx = common::make_example_context_with_cells(4);

    // Place driver and consumers on BELs with intra-tile switch connectivity.
    let (driver_bel, consumers) = find_routable_lut4_bels(&ctx);
    let cell0 = ctx.design.cell_by_name(ctx.id("cell_0")).unwrap();
    assert!(ctx.bind_bel(driver_bel, cell0, PlaceStrength::Placer));
    for (i, &consumer_bel) in consumers.iter().take(3).enumerate() {
        let cell_name = ctx.id(&format!("cell_{}", i + 1));
        let cell_idx = ctx.design.cell_by_name(cell_name).unwrap();
        assert!(ctx.bind_bel(consumer_bel, cell_idx, PlaceStrength::Placer));
    }

    let router_cfg = Router1Cfg::default();
    let net_name = ctx.id("net_0");
    let net_idx = ctx.design.net_by_name(net_name).unwrap();

    // Route just net_0 via route_nets
    Router1
        .route_nets(&mut ctx, &router_cfg, &[net_idx])
        .expect("routing net subset should succeed");

    let net = ctx.net(net_idx);
    assert!(
        net.wires().len() >= 2,
        "routed net should have wires, got {}",
        net.wires().len()
    );
}

#[test]
fn route_all_via_trait() {
    let mut ctx = common::make_example_context_with_cells(4);

    // Place driver and consumers on BELs with intra-tile switch connectivity.
    let (driver_bel, consumers) = find_routable_lut4_bels(&ctx);
    let cell0 = ctx.design.cell_by_name(ctx.id("cell_0")).unwrap();
    assert!(ctx.bind_bel(driver_bel, cell0, PlaceStrength::Placer));
    for (i, &consumer_bel) in consumers.iter().take(3).enumerate() {
        let cell_name = ctx.id(&format!("cell_{}", i + 1));
        let cell_idx = ctx.design.cell_by_name(cell_name).unwrap();
        assert!(ctx.bind_bel(consumer_bel, cell_idx, PlaceStrength::Placer));
    }

    let router_cfg = Router1Cfg::default();
    Router1
        .route(&mut ctx, &router_cfg)
        .expect("full routing should succeed");

    // Verify all routable nets have wires
    let net_name = ctx.id("net_0");
    let net_idx = ctx.design.net_by_name(net_name).unwrap();
    let net = ctx.net(net_idx);
    assert!(
        net.wires().len() >= 2,
        "net_0 should be routed after route(), got {} wires",
        net.wires().len()
    );
}
